# From 0008_reimbursement_receipt_word_merge
def enable_reimbursement_receipt_word_merge(apps, schema_editor):
    FormChannel = apps.get_model('clubs', 'FormChannel')
    FormField = apps.get_model('clubs', 'FormField')

    channel = FormChannel.objects.filter(slug='reimbursement').first()
    if not channel:
        return

    field = FormField.objects.filter(channel=channel, field_key='receipt_file').first()
    if not field:
        return

    validation = dict(field.validation or {})
    validation.update({
        'allowed_extensions': ['.pdf', '.jpg', '.jpeg', '.png', '.docx'],
        'max_size_mb': validation.get('max_size_mb') or 20,
        'allow_multiple': True,
        'merge_to_word': True,
    })
    field.validation = validation
    field.save(update_fields=['validation'])

