    for submission in FormSubmission.objects.filter(models.Q(public_id__isnull=True) | models.Q(public_id='')):
        public_id = uuid.uuid4().hex[:16]
        while public_id in used:
            public_id = uuid.uuid4().hex[:16]
        used.add(public_id)
        submission.public_id = public_id
        submission.save(update_fields=['public_id'])

