# From 0011_normalize_existing_submission_files
def normalize_existing_submission_files(apps, schema_editor):
    FormSubmission = apps.get_model('clubs', 'FormSubmission')

    submissions = FormSubmission.objects.prefetch_related('uploaded_files__field')
    for submission in submissions:
        files_by_field = defaultdict(list)
        generated_files = []
        for uploaded in submission.uploaded_files.all():
            if uploaded.is_generated:
                generated_files.append(uploaded)
            else:
                files_by_field[uploaded.field_id].append(uploaded)

        for field_id, uploaded_files in files_by_field.items():
            uploaded_files.sort(key=lambda item: (item.uploaded_at, item.id))
            total = len(uploaded_files)
            for index, uploaded in enumerate(uploaded_files, start=1):
                field = uploaded.field
                source_name = uploaded.source_name or uploaded.original_name or os.path.basename(uploaded.file.name)
                ext = os.path.splitext(source_name)[1].lower()
                display_name = f"{safe_filename_part(field.label)}{index if total > 1 else ''}{ext}"
                target = os.path.join('form_submissions', submission.public_id or str(submission.id), display_name)
                storage = uploaded.file.storage
                uploaded.file.name = move_file(storage, uploaded.file.name, target)
                uploaded.original_name = display_name
                if not uploaded.source_name:
                    uploaded.source_name = source_name
                uploaded.save(update_fields=['file', 'original_name', 'source_name'])

        for uploaded in generated_files:
            field = uploaded.field
            display_name = f'{safe_filename_part(field.label)}-合并文档.docx'
            target = os.path.join('form_submissions', submission.public_id or str(submission.id), display_name)
            storage = uploaded.file.storage
            uploaded.file.name = move_file(storage, uploaded.file.name, target)
            uploaded.original_name = display_name
            uploaded.save(update_fields=['file', 'original_name'])


